mapper.update:
/* wms-wif-dasapi-sql-oracle.xml - updateOutboundHeaderClassIfCntrBarcode - 출고상세 / 출고마감 IF 송신 데이터 조회 */
UPDATE TWORK_INFO_OB_HD
SET CLASSIFCNTRBARCODE = #{classifToteBrcd}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBHDKEY = #{obHdKey}

mapper.select:
/* wms-wif-dasapi-sql-oracle.xml - selectOutboundHeaderByDasToteClose - 출고헤더 처리여부 확인 BY 분류TOTE 마감 수신 */
SELECT
	CTKEY
	,OWKEY
	,OBHDKEY
	,OBSTATUSCD
FROM TWORK_INFO_OB_HD
WHERE CTKEY = #{ctKey}
AND OWKEY = #{owKey}
AND OBHDKEY = #{obHdKey}

mapper.update:
/* wms-wif-dasapi-sql-oracle.xml - updateOutboundDetailByDasToteClose - 출고상세 UPDATE BY 분류TOTE 마감 수신 */
UPDATE TWORK_INFO_OB_DT
SET OBDTSTATUSCD = #{obDtStatusCd}
	,CLASSIFSQTY = CLASSIFSQTY + #{qty}
WHERE CTKEY = #{ctKey}
AND OWKEY = #{owKey}
AND OBHDKEY = #{obHdKey}
AND ICKEY = #{icKey}

/* wms-wif-dasapi-sql-oracle.xml - updateOutboundHeaderStatusCdByDasToteClose - 출고헤더 UPDATE BY 분류TOTE 마감 수신 */
UPDATE TWORK_INFO_OB_HD
SET OBSTATUSCD = #{obStatusCd}
	,CLASSIFWKDATE = #{prcsTime}
	,CLASSIFWKURKEY = #{userId}
WHERE CTKEY = #{ctKey}
AND OWKEY = #{owKey}
AND OBHDKEY = #{obHdKey}

mapper.select:
/* wms-wif-dasapi-sql-oracle.xml - selectOutboundHeaderByRobDasBoxAdd - 출고헤더 조회 BY 로봇DAS 포장박스 추가 */
SELECT
	CTKEY
	,OWKEY
	,OBHDKEY
	,OBSTATUSCD
    ,DLVRYCORPCD
FROM TWORK_INFO_OB_HD
WHERE CTKEY = #{ctKey}
AND OWKEY = #{owKey}
AND OBHDKEY = #{obHdKey}
AND WKTYPECD = 'RW' /* 2026-01-26 KJH 덕용 로봇박스추가 불가 */

mapper.update:
/* wms-wif-dasapi-sql-oracle.xml - updateOutboundDetailByRobDas - 출고상세 UPDATE BY 로봇DAS (분류수량 +) */
UPDATE TWORK_INFO_OB_DT
SET OBDTSTATUSCD = #{obdtstatuscd}
	,CLASSIFSQTY = CLASSIFSQTY + #{topakqty}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBHDKEY = #{obhdkey}
AND OBDTKEY = #{obdtkey}

mapper.select:
/* wms-wif-dasapi-sql-oracle.xml - selectOutboundHeaderByRobDasBoxPackingComplete - 출고헤더 조회 BY 로봇DAS 출고완료 */
SELECT
	CTKEY
	,OWKEY
	,OBHDKEY
	,OBSTATUSCD
	,PREOBHDKEY
	,WKTYPECD
FROM TWORK_INFO_OB_HD
WHERE CTKEY = #{ctKey}
AND OWKEY = #{owKey}
AND OBHDKEY = #{obHdKey}

/* wms-wif-dasapi-sql-oracle.xml - selectOutboundDetailByRobDasBoxPackingComplete - 출고상세 조회 BY 로봇DAS 출고완료 */
SELECT
	OD.CTKEY
	,OD.OWKEY
	,OD.OBHDKEY
	,OD.OBDTKEY
FROM TWORK_INFO_OB_HD OH
	INNER JOIN TWORK_INFO_OB_DT OD
		ON OH.CTKEY = OD.CTKEY
		AND OH.OWKEY = OD.OWKEY
		AND OH.OBHDKEY = OD.OBHDKEY
WHERE OD.CTKEY = #{ctKey}
AND OD.OWKEY = #{owKey}
AND OD.OBHDKEY = #{obHdKey}
AND OD.ICKEY = #{icKey}
